using BgCommon.Script.Runtime.Configuration;using BgCommon.Script.Runtime.Utilities;namespace BgCommon.Script.Runtime.DotNet;/// <summary>/// 用于解析 .NET 安装路径的解析器类./// </summary>public class DotNetPathResolver{    /// <summary>    /// .NET 可执行文件的名称.    /// </summary>    private static readonly string DotNetExeName = PlatformUtil.IsOSWindows() ? "dotnet.exe" : "dotnet";    /// <summary>    /// Initializes a new instance of the <see cref="DotNetPathResolver"/> class.    /// </summary>    public DotNetPathResolver()    {    }    /// <summary>    /// 验证指定的路径是否为有效的 .NET SDK 根目录.    /// </summary>    /// <param name="path">待验证的路径字符串.</param>    /// <returns>如果是有效目录则返回 true，否则返回 false.</returns>    public static bool IsValidDotNetSdkRootDirectory(string? path)    {        // 检查路径是否为空或目录是否存在        if (path == null || !Directory.Exists(path))        {            return false;        }        // 确认目录中是否存在 dotnet 可执行文件        string executablePath = Path.Combine(path, DotNetExeName);        return File.Exists(executablePath);    }    /// <summary>    /// 查找 .NET 的安装目录.    /// </summary>    /// <param name="settings">应用程序配置设置接口.</param>    /// <returns>包含搜索步骤和解析路径的报告对象.</returns>    public DotNetPathReport FindDotNetInstallDir(IApplicationSettingsValues settings)    {        ArgumentNullException.ThrowIfNull(settings, nameof(settings));        DotNetPathReport pathReport = new DotNetPathReport();        // 优先检查用户是否在设置中明确指定了 SDK 路径        if (!string.IsNullOrWhiteSpace(settings.DotNetSdkDirectoryPath))        {            pathReport.AddSearchStep(settings.DotNetSdkDirectoryPath);            // 如果用户显式设置了此项，则不再进行后续自动检测            return pathReport;        }        // 尝试从 Shell 环境获取        this.GetDotNetPathFromShell(pathReport);        // 尝试从常见安装位置获取        this.GetDotNetPathFromCommonLocations(pathReport);        return pathReport;    }    /// <summary>    /// 通过 Shell 执行命令的方式尝试获取 .NET 路径.    /// </summary>    /// <param name="report">路径搜索报告对象.</param>    private void GetDotNetPathFromShell(DotNetPathReport report)    {        try        {            // 尝试通过启动 dotnet --version 来定位可执行文件            ProcessStartInfo startInfo = new ProcessStartInfo            {                UseShellExecute = true,                CreateNoWindow = true,                WindowStyle = ProcessWindowStyle.Hidden,                FileName = DotNetExeName,                Arguments = "--version",                RedirectStandardOutput = false, // 注意：UseShellExecute 为 true 时通常不能重定向            }.CopyCurrentEnvironmentVariables();            using var dotNetProcess = Process.Start(startInfo);            // 获取进程主模块的文件路径            string? executablePath = dotNetProcess?.MainModule?.FileName;            // 验证获取到的路径是否确实以 dotnet 结尾，防止指向了错误的 Shell 程序            if (executablePath?.EndsWith(DotNetExeName) != true)            {                return;            }            string? directoryPath = Path.GetDirectoryName(executablePath);            if (directoryPath == null)            {                return;            }            report.AddSearchStep(directoryPath);        }        catch        {            // 查找失败则忽略，继续后续步骤        }    }    /// <summary>    /// 从操作系统常见的预定义位置尝试获取 .NET 路径.    /// </summary>    /// <param name="report">路径搜索报告对象.</param>    private void GetDotNetPathFromCommonLocations(DotNetPathReport report)    {        // 按优先级排序的候选目录列表        List<string?> candidateDirectories = new List<string?>        {            // 环境变量具有最高优先级            Environment.GetEnvironmentVariable("DOTNET_ROOT"),            Environment.GetEnvironmentVariable("DOTNET_INSTALL_DIR"),        };        // 根据操作系统添加常见的安装路径        if (PlatformUtil.IsOSWindows())        {            candidateDirectories.Add(@"C:\Program Files\dotnet\x64");            candidateDirectories.Add(@"C:\Program Files\dotnet");        }        else        {            candidateDirectories.Add("/usr/local/share/dotnet"); // macOS 默认路径            candidateDirectories.Add("/usr/share/dotnet");            candidateDirectories.Add("/usr/lib/dotnet");            candidateDirectories.Add("/usr/lib64/dotnet");            candidateDirectories.Add("/opt/dotnet");        }        // 添加用户目录下的 .dotnet 隐藏文件夹        candidateDirectories.Add(Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.UserProfile), ".dotnet"));        foreach (string? currentPath in candidateDirectories)        {            if (string.IsNullOrWhiteSpace(currentPath))            {                continue;            }            report.AddSearchStep(currentPath);        }    }}/// <summary>/// .NET 路径搜索报告类./// </summary>public class DotNetPathReport{    /// <summary>    /// Initializes a new instance of the <see cref="DotNetPathReport"/> class.    /// </summary>    public DotNetPathReport()    {    }    /// <summary>    /// Gets or sets 解析后的 .NET 安装路径.    /// </summary>    public DirectoryPath? ResolvedPath { get; set; }    /// <summary>    /// Gets 搜索过程中经历的步骤列表.    /// </summary>    public List<SearchStep> SearchSteps { get; } = new();    /// <summary>    /// 向报告中添加一个搜索步骤，并根据目录状态更新解析结果.    /// </summary>    /// <param name="dir">待检查的目录路径.</param>    public void AddSearchStep(DirectoryPath dir)    {        // 避免重复检查相同的路径        if (this.SearchSteps.Any(x => x.Location == dir))        {            return;        }        // 验证目录是否存在        if (!dir.Exists())        {            this.SearchSteps.Add(new SearchStep(dir, SearchStepResult.DirectoryNotFound));        }        // 验证目录内是否存在有效的 .NET SDK        else if (!DotNetPathResolver.IsValidDotNetSdkRootDirectory(dir.Path))        {            this.SearchSteps.Add(new SearchStep(dir, SearchStepResult.NoInstallationFound));        }        else        {            // 找到有效路径            this.SearchSteps.Add(new SearchStep(dir, SearchStepResult.Valid));            this.ResolvedPath = dir;        }    }}/// <summary>/// 表示搜索过程中的单个步骤记录./// </summary>/// <param name="Location">搜索的路径位置.</param>/// <param name="Result">该位置的搜索结果状态.</param>public record SearchStep(DirectoryPath Location, SearchStepResult Result);/// <summary>/// 搜索步骤的结果枚举./// </summary>public enum SearchStepResult{    /// <summary>    /// 未找到指定的目录.    /// </summary>    DirectoryNotFound,    /// <summary>    /// 目录存在但未发现有效的 .NET 安装.    /// </summary>    NoInstallationFound,    /// <summary>    /// 找到了有效的 .NET 安装.    /// </summary>    Valid,}